char s[] = "Hello123";
int letters = 0, digits = 0;
for (int i = 0; s[i] != '\0'; i++) {
    if (s[i] >= 'a' && s[i] <= 'z' || s[i] >= 'A' && s[i] <= 'Z')
        letters++;
    else if (s[i] >= '0' && s[i] <= '9')
        digits++;
}
printf("letters: %d, digits: %d\n", letters, digits);
// letters: 5, digits: 3

